<?php $total=array_sum(array_column($items,'total'));$mode=setting('shipping_mode','manual');$manualUnavailable=$mode==='manual'&&!$zones;?><section class="checkout"><div><span class="eyebrow">Satu langkah lagi</span><h1>Tujuan pesanan</h1><p>Isi data berikut. Tombol terakhir membuka WhatsApp dengan ringkasan pesanan.</p><form method="post" action="<?=url('/checkout')?>" class="stack" id="checkout-form"><?=csrf_field()?><div class="form-grid"><label>Nama lengkap<input name="name" autocomplete="name" required></label><label>Nomor WhatsApp<input type="tel" inputmode="tel" autocomplete="tel" name="phone" pattern="62[0-9]{8,13}" placeholder="628123456789" required><small>Gunakan format 628xxxxxxxxxx.</small></label><label class="wide">Email opsional<input type="email" autocomplete="email" name="email"></label></div><label>Alamat lengkap<textarea name="address" autocomplete="street-address" rows="4" placeholder="Nama jalan, nomor, RT/RW, kecamatan, kota, kode pos" required></textarea></label><?php if($mode==='manual'&&$zones):?><label>Zona pengiriman<select name="shipping_zone" required><option value="">Pilih zona pengiriman</option><?php foreach($zones as $z):?><option value="<?=$z['id']?>"><?=e($z['name'])?> · mulai <?=money($z['base_cost'])?></option><?php endforeach?></select></label><?php elseif($manualUnavailable):?><div class="notice error" role="alert">Tarif pengiriman belum diatur toko. Hubungi toko sebelum melanjutkan checkout.</div><?php elseif($mode==='rajaongkir'):?><div class="stack shipping-checkout"><label for="destination-search">Kecamatan atau kelurahan tujuan<input id="destination-search" placeholder="Ketik minimal 3 huruf, contoh: Coblong" autocomplete="off"></label><div id="destination-results" class="destination-results" role="listbox"></div><input type="hidden" name="destination_id" id="destination-id"><input type="hidden" name="destination_label" id="destination-label"><button type="button" class="secondary-button" id="check-rates" disabled>Cek pilihan kurir</button><label>Layanan pengiriman<select name="shipping_service" id="shipping-service" required><option value="">Cari tujuan terlebih dahulu</option></select></label><small id="shipping-message" aria-live="polite">Tarif dihitung langsung dari RajaOngkir V2.</small></div><?php endif?><label>Catatan untuk toko (opsional)<textarea name="notes" placeholder="Contoh: waktu pengiriman atau petunjuk alamat"></textarea></label><div class="checkout-total"><span>Subtotal</span><strong><?=money($total)?></strong><span>Ongkir</span><strong id="shipping-total">Pilih layanan</strong><span>Total akhir</span><strong id="grand-total" data-subtotal="<?=$total?>"><?=money($total)?></strong></div><button class="button button-large" id="checkout-submit" <?=$manualUnavailable?'disabled':''?>>Buat pesanan dan buka WhatsApp</button></form></div><aside class="order-note"><span>Ringkasan</span><?php foreach($items as $x):?><p><b><?=$x['quantity']?>×</b> <?=e($x['name'].' · '.$x['variant_name'])?><strong><?=money($x['total'])?></strong></p><?php endforeach?><div>Subtotal <strong><?=money($total)?></strong></div><small>Pesanan belum mengurangi stok sebelum dikonfirmasi toko.</small></aside></section>
<?php if($mode==='rajaongkir'):?><script>const search=document.querySelector('#destination-search'),results=document.querySelector('#destination-results'),destinationId=document.querySelector('#destination-id'),rateButton=document.querySelector('#check-rates'),service=document.querySelector('#shipping-service'),message=document.querySelector('#shipping-message'),submit=document.querySelector('#checkout-submit'),shipTotal=document.querySelector('#shipping-total'),grand=document.querySelector('#grand-total');let timer;submit.disabled=true;search.addEventListener('input',()=>{clearTimeout(timer);destinationId.value='';rateButton.disabled=true;submit.disabled=true;if(search.value.trim().length<3){results.innerHTML='';message.textContent='Ketik minimal 3 huruf.';return}timer=setTimeout(async()=>{message.textContent='Mencari tujuan...';try{const r=await fetch(`<?=url('/api/shipping/destinations')?>?q=${encodeURIComponent(search.value)}`),j=await r.json();if(!r.ok)throw new Error(j.message);results.innerHTML=j.data.map(x=>`<button type="button" role="option" data-id="${x.id}" data-label="${x.label||''}">${x.label||[x.subdistrict,x.district,x.city,x.province].filter(Boolean).join(', ')}</button>`).join('')||'<span>Lokasi tidak ditemukan.</span>';message.textContent='Pilih satu lokasi dari hasil.'}catch(e){results.innerHTML='';message.textContent=e.message}},400)});results.addEventListener('click',e=>{const b=e.target.closest('button');if(!b)return;destinationId.value=b.dataset.id;search.value=b.textContent;results.innerHTML='';rateButton.disabled=false;message.textContent='Tujuan dipilih. Tekan Cek pilihan kurir.'});rateButton.addEventListener('click',async()=>{rateButton.disabled=true;rateButton.textContent='Mengambil tarif...';const body=new FormData();body.append('_token','<?=csrf_token()?>');body.append('destination_id',destinationId.value);try{const r=await fetch('<?=url('/api/shipping/rates')?>',{method:'POST',body}),j=await r.json();if(!r.ok)throw new Error(j.message);service.innerHTML='<option value="">Pilih layanan</option>'+j.data.map(x=>`<option value="${x.courier}|${x.service}" data-cost="${x.cost}">${x.courier_name} ${x.service} · ${new Intl.NumberFormat('id-ID',{style:'currency',currency:'IDR',maximumFractionDigits:0}).format(x.cost)} · ${x.etd||'Estimasi tidak tersedia'}</option>`).join('');message.textContent=j.data.length?'Pilih tarif yang sesuai.':'Kurir tidak tersedia.'}catch(e){message.textContent=e.message}finally{rateButton.disabled=false;rateButton.textContent='Cek pilihan kurir'}});service.addEventListener('change',()=>{const o=service.selectedOptions[0],cost=Number(o?.dataset.cost||0);if(!cost){submit.disabled=true;shipTotal.textContent='Pilih layanan';grand.textContent=new Intl.NumberFormat('id-ID',{style:'currency',currency:'IDR',maximumFractionDigits:0}).format(Number(grand.dataset.subtotal));return}const f=new Intl.NumberFormat('id-ID',{style:'currency',currency:'IDR',maximumFractionDigits:0});shipTotal.textContent=f.format(cost);grand.textContent=f.format(Number(grand.dataset.subtotal)+cost);submit.disabled=false});</script><?php endif?>
